const pedido = $json.body ?? $json;

const prompt = `Você é um consultor de vendas especialista de uma loja virtual.
Sua missão é analisar o pedido recente de um cliente e gerar recomendações estratégicas com base nos produtos comprados e no valor total.

DADOS DO PEDIDO:
${JSON.stringify(pedido)}

REGRAS OBRIGATÓRIAS:
Retorne APENAS um objeto JSON válido.
Não adicione nenhuma formatação Markdown (como \`\`\`json), nem textos antes ou depois.
Utilize estritamente a estrutura abaixo:

{
  "perfilCliente": "Classifique o cliente (ex: Cliente Premium, Gamer, etc)",
  "recomendacoes": "Liste 3 produtos recomendados em uma única string separados por vírgula",
  "cupomDesconto": "Crie um código de cupom de desconto curto",
  "mensagemIA": "Escreva uma mensagem amigável agradecendo a compra e informando o cupom"
}`;

return [{ json: { pedido, prompt } }];

const pedido = $('Montar Prompt').first().json.pedido;
const produtos = pedido.produtos || [];
const valorTotal = Number(pedido.valorTotal || 0);
const cliente = pedido.cliente || 'Cliente';

let perfilCliente = 'Cliente Regular';
if (valorTotal >= 2000) perfilCliente = 'Cliente Premium';
else if (produtos.some(p => /gamer|mouse|teclado|headset/i.test(p))) perfilCliente = 'Gamer';
else if (valorTotal >= 800) perfilCliente = 'Cliente Tech';

const catalogo = [
  'Teclado Mecânico',
  'Headset Gamer',
  'Mousepad XL',
  'Monitor 27"',
  'Webcam HD',
  'Suporte Notebook'
];

const recomendados = catalogo
  .filter(item => !produtos.includes(item))
  .slice(0, 3);

while (recomendados.length < 3) {
  recomendados.push('Mousepad XL');
}

const cupomBase = cliente.toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 6) || 'LOJA';
const cupomDesconto = `${cupomBase}10`;

const resposta = {
  perfilCliente,
  recomendacoes: recomendados.join(', '),
  cupomDesconto,
  mensagemIA: `Olá ${cliente}! Obrigado pela sua compra. Preparamos ofertas especiais para você. Use o cupom ${cupomDesconto} e ganhe 10% OFF na próxima compra!`
};

return [{ json: resposta }];

const raw = $input.first().json;
let parsed = raw;

if (typeof raw.output === 'string') {
  let text = raw.output.trim();
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  }
  parsed = JSON.parse(text);
}

const required = ['perfilCliente', 'recomendacoes', 'cupomDesconto', 'mensagemIA'];
for (const field of required) {
  if (!parsed[field] || String(parsed[field]).trim() === '') {
    throw new Error(`Campo obrigatório ausente: ${field}`);
  }
}

return [{ json: parsed }];
